import os
import requests
from flask import Flask, request, escape
app = Flask(__name__)


@app.route('/')
def hello():
    return 'Hello World!'


@app.route('/welcome')
def welcome(name=None):
    return '''
    <!DOCTYPE html>
    <html lang="en">
        <head>
            <meta charset="UTF-8">
            <title>Welcome</title>
        </head>
        <body style="background: #333; color:#fff;">
            <div class="container">
                <h1>Welcome to the Dashboard</h1>
                <p>Name: {}</p>
                <p>Bio: {}</p>
                <p>Location: {}</p>
                <p>Status Message: {}</p>
            </div>
        </body>
    </html>'''.format(escape(name), escape(request.args['bio']), escape(request.args['location']), escape(request.args['status']))


if __name__ == "__main__":
    app.run()